PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?kingdom
WHERE {
  {
    SELECT ?species ?kingdom
    WHERE {
      ?species a dbo:Species ;
              dbo:conservationStatus ?status ;
              dbo:kingdom ?kingdom .
      FILTER (regex(str(?status), "Endangered|Critically endangered", "i"))
    }
  }
}
GROUP BY ?kingdom
ORDER BY DESC(COUNT(DISTINCT ?species))
LIMIT 3

